176	/// A request for a `main/*` content pane, resolved to the prover.
177	pub enum MainReq<'a> {
178	    Help,
179	    Message,
180	    Rules,
181	    Tactic,
182	    Cases { refined: bool, level: usize, n: usize },
183	    Lemma(&'a str),
184	    Proof { lemma: &'a str, path: &'a [String] },
185	    /// Diff-mode proof view.
186	    DiffProof { lemma: &'a str, path: &'a [String] },
187	    /// Diff construction/deconstruction rules view.
188	    DiffRules,
189	}
