266	/// The interactive server's state: the version map plus the monotonic next-index
267	/// counter. One global index namespace covers every loaded/derived theory-version.
268	pub struct Server<T: ProverOps> {
269	    ops: T,
270	    versions: BTreeMap<u64, T::Theory>,
271	    next_index: u64,
272	}
273	
274	impl<T: ProverOps> Server<T> {
275	    /// Create a server holding `base` as version 1.
276	    pub fn new(ops: T, base: T::Theory) -> Server<T> {
277	        let mut versions = BTreeMap::new();
278	        versions.insert(1, base);
279	        Server { ops, versions, next_index: 2 }
280	    }
281	
282	    /// Version indices currently allocated (ascending). All are resolvable.
283	    pub fn versions(&self) -> Vec<u64> {
284	        self.versions.keys().copied().collect()
285	    }
286	
287	    fn resolve(&self, index: &Index) -> Option<u64> {
288	        match index {
289	            Index::Num(v) if self.versions.contains_key(v) => Some(*v),
290	            _ => None,
291	        }
292	    }
293	
294	    fn commit_new_version(&mut self, thy: T::Theory) -> u64 {
295	        let new_index = self.next_index;
296	        self.next_index += 1;
297	        self.versions.insert(new_index, thy);
298	        new_index
299	    }
300	
301	    /// Dispatch a request across the whole surface, mutating version state as
302	    /// observed.
303	    pub fn dispatch(&mut self, req: &Request) -> Response {
304	        match Toplevel::parse(req.path) {
305	            Toplevel::Root => self.root(req),
306	            Toplevel::Robots => self.get_only(req, || Response::text(assets::ROBOTS_TXT.to_string())),
307	            Toplevel::Favicon => self.get_only(req, || Response::see_other(assets::FAVICON_TARGET.to_string())),
308	            Toplevel::Kill => self.kill(req),
309	            Toplevel::Static(segs) => self.static_asset(req, &segs),
310	            Toplevel::Thy(route) => self.thy(req, &route),
311	            Toplevel::Other(_) => Response::not_found(req.path),
312	        }
313	    }
314	
315	    /// Run `f` for a GET; a non-GET on a GET-only route answers `405`.
316	    fn get_only(&self, req: &Request, f: impl FnOnce() -> Response) -> Response {
317	        match req.method {
318	            HttpMethod::Get => f(),
319	            other => Response::bad_method(other),
320	        }
321	    }
322	
323	    // ---- top-level routes ------------------------------------------------
324	
325	    fn root(&mut self, req: &Request) -> Response {
326	        match req.method {
327	            HttpMethod::Get => Response::html(self.render_index(Flash::None)),
328	            HttpMethod::Post => {
329	                let uploaded = req.field("uploadedTheory");
330	                let loaded = if uploaded.is_empty() {
331	                    None
332	                } else {
333	                    self.ops.load_theory(uploaded)
334	                };
335	                match loaded {
336	                    Some(thy) => {
337	                        self.commit_new_version(thy);
338	                        Response::html(self.render_index(Flash::Loaded))
339	                    }
340	                    None => Response::html(self.render_index(Flash::PostFailed)),
341	                }
342	            }
343	        }
344	    }
345	
346	    /// Render the index page for the current version set. Rows are emitted in
347	    /// ascending index order; the reference server's exact row *ordering* and the
348	    /// per-row time/origin are non-deterministic (prover/environment concerns).
349	    fn render_index(&self, flash: Flash) -> String {
350	        let mut version = String::new();
351	        let mut rows: Vec<RootRow> = Vec::with_capacity(self.versions.len());
352	        // Owned strings must outlive the borrowed RootRow slice.
353	        let mut owned: Vec<(u64, String, String, bool, String)> = Vec::new();
354	        for (&idx, thy) in &self.versions {
355	            let m = self.ops.meta(thy);
356	            let rm = self.ops.root_meta(thy);
357	            if version.is_empty() {
358	                version = m.version.clone();
359	            }
360	            owned.push((idx, m.name, rm.time, rm.modified, rm.origin));
361	        }
362	        for (idx, name, time, modified, origin) in &owned {
363	            rows.push(RootRow { index: *idx, name, time, modified: *modified, origin });
364	        }
365	        page::render_root(flash, &version, &rows)
366	    }
367	
368	    fn kill(&self, req: &Request) -> Response {
369	        match req.method {
370	            HttpMethod::Get => match req.query_param("path") {
371	                Some(_) => Response::text(assets::KILL_CANCELED.to_string()),
372	                None => Response::invalid_args(&[assets::KILL_NO_PATH_MSG]),
373	            },
374	            other => Response::bad_method(other),
375	        }
376	    }
377	
378	    fn static_asset(&self, req: &Request, segs: &[String]) -> Response {
379	        match req.method {
380	            HttpMethod::Get => match self.ops.static_file(segs) {
381	                Some(bytes) => {
382	                    let joined = segs.join("/");
383	                    // Asset bytes are opaque environment data; a UTF-8 asset is
384	                    // reproduced exactly, a binary asset is streamed at integration.
385	                    let body = String::from_utf8_lossy(&bytes).into_owned();
386	                    Response::base(200, assets::static_content_type(&joined), body)
387	                }
388	                None => Response::static_missing(),
389	            },
390	            other => Response::bad_method(other),
391	        }
392	    }
393	
394	    // ---- theory-scoped routes -------------------------------------------
395	
396	    fn thy(&mut self, req: &Request, route: &Route) -> Response {
397	        let index = match self.resolve(&route.index) {
398	            Some(v) => v,
399	            None => return Response::not_found(req.path),
400	        };
401	        let kind = shell_kind(&route.theory_kind);
402	        match (req.method, &route.handler) {
403	            // Proof operations (allocate a new version) — intercept before reads.
404	            (HttpMethod::Get, Handler::Main(Main::Method { lemma, n, path })) => {
405	                self.proof_method(kind, index, &lemma.clone(), *n, &path.clone(), false)
406	            }
407	            (HttpMethod::Get, Handler::Main(Main::DiffMethod { lemma, n, path })) => {
408	                self.proof_method(kind, index, &lemma.clone(), *n, &path.clone(), true)
409	            }
410	            (HttpMethod::Get, Handler::Main(m)) => self.get_main(index, m),
411	            (HttpMethod::Get, Handler::Overview(tail)) => {
412	                self.get_overview(kind, index, &OverviewView::parse(tail))
413	            }
414	            (HttpMethod::Get, Handler::Autoprove(tail)) => match Autoprove::parse(tail) {
415	                Some(ap) => {
416	                    let (thy, focus) = self.ops.autoprove(&self.versions[&index], &ap);
417	                    let new = self.commit_new_version(thy);
418	                    Response::json(envelope::render_redirect(&overview_proof_path(kind, new, &ap.lemma, &focus, false)))
419	                }
420	                None => Response::not_found(req.path),
421	            },
422	            (HttpMethod::Get, Handler::AutoproveDiff(tail)) => match AutoproveDiff::parse(tail) {
423	                Some(ap) => {
424	                    let (thy, focus) = self.ops.autoprove_diff(&self.versions[&index], &ap);
425	                    let new = self.commit_new_version(thy);
426	                    Response::json(envelope::render_redirect(&overview_proof_path(kind, new, &ap.lemma, &focus, true)))
427	                }
428	                None => Response::not_found(req.path),
429	            },
430	            (HttpMethod::Get, Handler::AutoproveAll(tail)) => match AutoproveAll::parse(tail) {
431	                Some(ap) => {
432	                    let thy = self.ops.autoprove_all(&self.versions[&index], &ap);
433	                    let new = self.commit_new_version(thy);
434	                    Response::json(envelope::render_redirect(&format!("/thy/{}/{}/overview/help", kind.path(), new)))
435	                }
436	                None => Response::not_found(req.path),
437	            },
438	            (HttpMethod::Get, Handler::Next(tail)) => self.get_nav(index, NavDir::Next, tail, req.path),
439	            (HttpMethod::Get, Handler::Prev(tail)) => self.get_nav(index, NavDir::Prev, tail, req.path),
440	            (HttpMethod::Get, Handler::Source) | (HttpMethod::Get, Handler::Message) => {
441	                Response::text(self.ops.source_text(&self.versions[&index]))
442	            }
443	            (HttpMethod::Get, Handler::Download(_)) => {
444	                Response::octet(self.ops.source_text(&self.versions[&index]))
445	            }
446	            (HttpMethod::Get, Handler::Intdot(tail)) => self.get_intdot(kind, index, tail),
447	            (HttpMethod::Get, Handler::InteractiveGraphDef(tail)) => {
448	                Response::text(self.ops.graph_dot(&self.versions[&index], tail))
449	            }
450	            // Wrong method on GET-only theory routes.
451	            (HttpMethod::Post, Handler::Source)
452	            | (HttpMethod::Post, Handler::Message)
453	            | (HttpMethod::Post, Handler::Download(_)) => Response::bad_method(HttpMethod::Post),
454	
455	            // In-place mutating POSTs.
456	            (HttpMethod::Post, Handler::Reload) => {
457	                let new_thy = self.ops.reload(&self.versions[&index]);
458	                self.versions.insert(index, new_thy);
459	                Response::json(envelope::render_redirect(&format!("/thy/{}/{}/overview/help", kind.path(), index)))
460	            }
461	            (HttpMethod::Get, Handler::Reload) => Response::bad_method(HttpMethod::Get),
462	            (HttpMethod::Post, Handler::GetAndAppend(_)) => {
463	                Response::json(envelope::render_alert(&self.ops.append_message(&self.versions[&index])))
464	            }
465	            (HttpMethod::Get, Handler::GetAndAppend(_)) => Response::bad_method(HttpMethod::Get),
466	            (HttpMethod::Post, Handler::Edit(tail)) => self.post_edit(kind, index, tail, req),
467	
468	            // del/path (both kinds) and verify (trace only). The theory-path parse
469	            // decides route-match (unparseable -> 404 for any method); a parseable
470	            // path with a non-GET method is a 405.
471	            (_, Handler::DelPath(segs)) => self.del_path(req.method, kind, index, segs, req.path),
472	            (_, Handler::Verify(segs)) => {
473	                if kind == ShellKind::Trace {
474	                    self.verify(req.method, index, segs, req.path)
475	                } else {
476	                    // `verify` is not registered for equiv theories: a miss for any method.
477	                    Response::not_found(req.path)
478	                }
479	            }
480	            _ => Response::not_found(req.path),
481	        }
482	    }
