484	    // ---- GET main/* : JSON envelopes ----
485	    fn get_main(&self, index: u64, m: &Main) -> Response {
486	        let thy = &self.versions[&index];
487	        let content = match m {
488	            Main::Help => self.ops.main_content(thy, index, &MainReq::Help),
489	            Main::Message => self.ops.main_content(thy, index, &MainReq::Message),
490	            Main::Rules => self.ops.main_content(thy, index, &MainReq::Rules),
491	            Main::DiffRules => self.ops.main_content(thy, index, &MainReq::DiffRules),
492	            Main::Tactic => self.ops.main_content(thy, index, &MainReq::Tactic),
493	            Main::Cases { refined, level, n } => {
494	                self.ops.main_content(thy, index, &MainReq::Cases { refined: *refined, level: *level, n: *n })
495	            }
496	            Main::Lemma(name) => self.ops.main_content(thy, index, &MainReq::Lemma(name)),
497	            Main::Proof { lemma, path } => {
498	                self.ops.main_content(thy, index, &MainReq::Proof { lemma, path })
499	            }
500	            Main::DiffProof { lemma, path } => {
501	                self.ops.main_content(thy, index, &MainReq::DiffProof { lemma, path })
502	            }
503	            Main::Edit(name) => {
504	                let src = self.ops.lemma_source(thy, name).unwrap_or_default();
505	                Content { html: forms::edit_form(name, &src), title: format!("Edit Lemma: {name}") }
506	            }
507	            Main::Add(pos) => Content { html: forms::add_form(pos), title: "Add new Lemma".to_string() },
508	            Main::Delete(name) => Content { html: forms::delete_form(name), title: format!("Delete {name}") },
509	            // Proof ops are intercepted in `thy`; unreachable read-side.
510	            Main::Method { .. } | Main::DiffMethod { .. } => return Response::not_found("method"),
511	            Main::Other(_) => return Response::not_found("main"),
512	        };
513	        Response::json(envelope::render_content(&content.html, &content.title))
514	    }
