569	    // ---- proof operations: new version + JSON {redirect}, or {alert} on failure ----
570	    fn proof_method(&mut self, kind: ShellKind, index: u64, lemma: &str, n: usize, path: &[String], diff: bool) -> Response {
571	        let applied = if diff {
572	            self.ops.apply_diff_method(&self.versions[&index], lemma, n, path)
573	        } else {
574	            self.ops.apply_method(&self.versions[&index], lemma, n, path)
575	        };
576	        match applied {
577	            Some((new_thy, focus)) => {
578	                let new = self.commit_new_version(new_thy);
579	                Response::json(envelope::render_redirect(&overview_proof_path(kind, new, lemma, &focus, diff)))
580	            }
581	            None => Response::json(envelope::render_alert(METHOD_FAILED_ALERT)),
582	        }
583	    }
584	
585	    // ---- del/path : delete a theory path (proof op — new version) ----
586	    /// Dispatch a `del/path/…` request. The theory-path tail parses mode-aware
587	    /// (`kind`); an unparseable tail is a `404` (for any method), a parseable tail
588	    /// with a non-GET method is a `405`. A deletable path (a lemma or proof node)
589	    /// allocates a fresh version and redirects to `overview/<same-path>`; every
590	    /// other outcome is a JSON alert whose text is selected by the path type.
591	    fn del_path(&mut self, method: HttpMethod, kind: ShellKind, index: u64, segs: &[String], path: &str) -> Response {
592	        let diff = kind == ShellKind::Equiv;
593	        let thy_path = match ThyPath::parse(segs, diff) {
594	            Some(tp) => tp,
595	            None => return Response::not_found(path),
596	        };
597	        if method != HttpMethod::Get {
598	            return Response::bad_method(method);
599	        }
600	        match thy_path {
601	            ThyPath::Lemma(name) => match self.ops.del_lemma_path(&self.versions[&index], &name) {
602	                Some(new_thy) => {
603	                    let new = self.commit_new_version(new_thy);
604	                    Response::json(envelope::render_redirect(&overview_lemma_path(kind, new, &name)))
605	                }
606	                None => Response::json(envelope::render_alert(envelope::DEL_LEMMA_FAILED_ALERT)),
607	            },
608	            ThyPath::Proof { lemma, path } => self.del_proof(kind, index, &lemma, &path, false),
609	            ThyPath::DiffProof { lemma, path } => self.del_proof(kind, index, &lemma, &path, true),
610	            ThyPath::Other => Response::json(envelope::render_alert(envelope::DEL_PATH_CANT_ALERT)),
611	        }
612	    }
613	
614	    fn del_proof(&mut self, kind: ShellKind, index: u64, lemma: &str, path: &[String], diff: bool) -> Response {
615	        match self.ops.del_proof_step(&self.versions[&index], lemma, path, diff) {
616	            Some(new_thy) => {
617	                let new = self.commit_new_version(new_thy);
618	                Response::json(envelope::render_redirect(&overview_proof_path(kind, new, lemma, path, diff)))
619	            }
620	            None => Response::json(envelope::render_alert(envelope::DEL_PROOF_STEP_FAILED_ALERT)),
621	        }
622	    }
623	
624	    // ---- verify : re-render a theory path (trace only; never mutates) ----
625	    /// Dispatch a `verify/…` request (trace theories only — the caller answers a
626	    /// `404` in equiv mode). The theory-path tail parses in the trace grammar; an
627	    /// unparseable tail is a `404`, a parseable tail with a non-GET method a `405`.
628	    /// A `proof/{lemma}[/path]` whose lemma is present redirects to
629	    /// `overview/proof/{lemma}[/path]` at the **same** version; every other path
630	    /// (including a proof path to an absent lemma) returns the theory help pane.
631	    fn verify(&self, method: HttpMethod, index: u64, segs: &[String], path: &str) -> Response {
632	        let thy_path = match ThyPath::parse(segs, false) {
633	            Some(tp) => tp,
634	            None => return Response::not_found(path),
635	        };
636	        if method != HttpMethod::Get {
637	            return Response::bad_method(method);
638	        }
639	        let thy = &self.versions[&index];
640	        match thy_path {
641	            ThyPath::Proof { lemma, path } if self.ops.lemma_present(thy, &lemma) => {
642	                Response::json(envelope::render_redirect(&overview_proof_path(
643	                    ShellKind::Trace, index, &lemma, &path, false,
644	                )))
645	            }
646	            _ => {
647	                let content = self.ops.main_content(thy, index, &MainReq::Help);
648	                Response::json(envelope::render_content(&content.html, &content.title))
649	            }
650	        }
651	    }
652	
653	    // ---- structural POST: mutate in place; 303 (or 200 form on edit/add failure) ----
654	    fn post_edit(&mut self, kind: ShellKind, index: u64, tail: &[String], req: &Request) -> Response {
655	        let (verb, name) = match tail {
656	            [v, n] => match EditVerb::parse(v) {
657	                Some(verb) => (verb, n.clone()),
658	                None => return Response::not_found(req.path),
659	            },
660	            _ => return Response::not_found(req.path),
661	        };
662	        let k = kind.path();
663	        match verb {
664	            EditVerb::Delete => match self.ops.delete_lemma(&self.versions[&index], &name) {
665	                Some(new_thy) => {
666	                    self.versions.insert(index, new_thy);
667	                    Response::see_other(format!("/thy/{k}/{index}/overview/help"))
668	                }
669	                // Lemma not found: theory unchanged, redirect to the delete view.
670	                None => Response::see_other(format!("/thy/{k}/{index}/overview/delete/{name}")),
671	            },
672	            EditVerb::Edit => {
673	                let text = req.field("lemma-text");
674	                match self.ops.edit_lemma(&self.versions[&index], &name, text) {
675	                    Some(new_thy) => {
676	                        self.versions.insert(index, new_thy);
677	                        Response::see_other(format!("/thy/{k}/{index}/overview/edit/{name}"))
678	                    }
679	                    None => self.get_overview(kind, index, &OverviewView::Edit(name)),
680	                }
681	            }
682	            EditVerb::Add => {
683	                let text = req.field("lemma-text");
684	                match self.ops.add_lemma(&self.versions[&index], &name, text) {
685	                    Some(new_thy) => {
686	                        self.versions.insert(index, new_thy);
687	                        Response::see_other(format!("/thy/{k}/{index}/overview/add/{name}"))
688	                    }
689	                    None => self.get_overview(kind, index, &OverviewView::Add(name)),
690	                }
691	            }
692	        }
693	    }
694	
695	    /// Apply a proof method that arrived as a parsed `Main::Method`. Exposed so a
696	    /// caller that pre-parses `main/method` can drive the version bump directly.
697	    pub fn apply_main_method(&mut self, index: u64, lemma: &str, n: usize, path: &[String]) -> Response {
698	        self.proof_method(ShellKind::Trace, index, lemma, n, path, false)
699	    }
700	}
701	
702	/// Map a URL theory-kind segment to a shell variant.
703	fn shell_kind(kind: &str) -> ShellKind {
704	    match kind {
705	        "equiv" => ShellKind::Equiv,
706	        _ => ShellKind::Trace,
707	    }
708	}
709	
710	/// Build a `del/path/lemma/{name}` redirect target: the `overview/lemma/{name}`
711	/// URL at version `index`.
712	fn overview_lemma_path(kind: ShellKind, index: u64, name: &str) -> String {
713	    format!("/thy/{}/{}/overview/lemma/{}", kind.path(), index, name)
714	}
715	
716	/// Build the redirect target for a proof operation: an `overview/proof/…` URL for
717	/// trace, or `overview/diffProof/…` for diff, at version `index`.
718	fn overview_proof_path(kind: ShellKind, index: u64, lemma: &str, focus: &[String], diff: bool) -> String {
719	    let handler = if diff { "diffProof" } else { "proof" };
720	    let mut s = format!("/thy/{}/{}/overview/{}/{}", kind.path(), index, handler, lemma);
721	    for seg in focus {
722	        s.push('/');
723	        s.push_str(seg);
724	    }
725	    s
726	}
