1	//! The full-page theory-view HTML shell (`overview/*`) and the index page (`/`).
2	//!
3	//! Observed structure (constant across theories after substituting the
4	//! parameters below): a fixed `<head>` of stylesheet/script links, a north header
5	//! bar, then four layout panes — west "Proof scripts", east "Debug information"
6	//! (always empty), and center "Visualization display". The west pane embeds the
7	//! proof-script markup (see [`crate::proofscript`]); the center pane embeds the
8	//! currently-selected main content HTML.
9	//!
10	//! The shell is shared between the ordinary trace view and the observational-
11	//! equivalence (diff) view: the only differences are the `<title>` prefix
12	//! (`Theory:` vs `DiffTheory:`), the `/thy/<kind>/` segment in every internal
13	//! link (`trace` vs `equiv`), and the presence of the Actions-menu "Append
14	//! modified lemmas" item (trace only). These are captured by [`ShellKind`].
15	//!
16	//! Scaffolding constants in `shell_template` are byte-exact copies of oracle
17	//! output. The body has no trailing newline (ends `</html>`).
18	
19	use crate::escape::html_escape;
20	use crate::shell_template::{
21	    APPEND_ITEM, PAGE_MID, PAGE_PREFIX, PAGE_TAIL, ROOT_TEMPLATE,
22	};
23	
24	/// Parameters that vary between rendered theory-view pages.
25	pub struct PageParams<'a> {
26	    /// Theory name, shown in `<title>…Theory: NAME</title>`.
27	    pub theory_name: &'a str,
28	    /// Resolved numeric theory index used in every internal URL.
29	    pub index: u64,
30	    /// Tamarin version string shown in the header (e.g. `"1.13.0"`).
31	    pub version: &'a str,
32	    /// Source filename used in the download / append links (e.g. `"foo.spthy"`).
33	    pub filename: &'a str,
34	}
35	
36	/// Which theory-view shell variant to render.
37	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
38	pub enum ShellKind {
39	    /// Ordinary trace analysis: `/thy/trace/`, `Theory:` title, append item present.
40	    Trace,
41	    /// Observational-equivalence (diff) analysis: `/thy/equiv/`, `DiffTheory:`
42	    /// title, no append item.
43	    Equiv,
44	}
45	
46	impl ShellKind {
47	    /// The `/thy/<kind>/` path segment.
48	    pub fn path(self) -> &'static str {
49	        match self {
50	            ShellKind::Trace => "trace",
51	            ShellKind::Equiv => "equiv",
52	        }
53	    }
54	    fn title_diff(self) -> &'static str {
55	        match self {
56	            ShellKind::Trace => "",
57	            ShellKind::Equiv => "Diff",
58	        }
59	    }
60	    fn append(self) -> &'static str {
61	        match self {
62	            ShellKind::Trace => APPEND_ITEM,
63	            ShellKind::Equiv => "",
64	        }
65	    }
66	}
67	
68	/// Render the trace theory-view page (the common case).
69	pub fn render_page(p: &PageParams, west_inner: &str, center_inner: &str) -> String {
70	    render_page_kind(ShellKind::Trace, p, west_inner, center_inner)
71	}
72	
73	/// Render the theory-view page for a given shell variant.
74	pub fn render_page_kind(
75	    kind: ShellKind,
76	    p: &PageParams,
77	    west_inner: &str,
78	    center_inner: &str,
79	) -> String {
80	    let idx = p.index.to_string();
81	    // Fill the append slot first so its own KIND/IDX/FILENAME slots are then
82	    // resolved by the scalar substitutions below.
83	    let prefix = PAGE_PREFIX
84	        .replace("§APPEND§", kind.append())
85	        .replace("§DIFF§", kind.title_diff())
86	        .replace("§NAME§", &html_escape(p.theory_name))
87	        .replace("§KIND§", kind.path())
88	        .replace("§IDX§", &idx)
89	        .replace("§VERSION§", p.version)
90	        .replace("§FILENAME§", p.filename);
91	    let mut out = String::with_capacity(
92	        prefix.len() + west_inner.len() + PAGE_MID.len() + center_inner.len() + PAGE_TAIL.len(),
93	    );
94	    out.push_str(&prefix);
95	    out.push_str(west_inner);
96	    out.push_str(PAGE_MID);
97	    out.push_str(center_inner);
98	    out.push_str(PAGE_TAIL);
99	    out
100	}
101	
102	/// A flash banner shown once at the top of the index page.
103	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
104	pub enum Flash {
105	    /// No banner (a plain `GET /`).
106	    None,
107	    /// `POST /` succeeded: a new theory was loaded.
108	    Loaded,
109	    /// `POST /` failed (e.g. no file / unparseable upload).
110	    PostFailed,
111	}
112	
113	impl Flash {
114	    fn html(self) -> &'static str {
115	        match self {
116	            Flash::None => "",
117	            Flash::Loaded => "<p class=\"message\">Loaded new theory!</p>",
118	            Flash::PostFailed => "<p class=\"message\">Post request failed.</p>",
119	        }
120	    }
121	}
122	
123	/// One row of the index page's theory table. `time` (load time) and `origin`
124	/// (source path) are non-deterministic and supplied verbatim by the caller.
125	pub struct RootRow<'a> {
126	    pub index: u64,
127	    pub name: &'a str,
128	    pub time: &'a str,
129	    /// `true` once the theory has been modified from its loaded state (rendered
130	    /// as an italicised `Modified`); `false` renders a plain `Original`.
131	    pub modified: bool,
132	    pub origin: &'a str,
133	}
134	
135	/// Render a single index-page theory row. The `Version` cell is a plain
136	/// `Original` or an (unclosed, as observed) `<em>Modified`.
137	pub fn render_root_row(r: &RootRow) -> String {
138	    let version_cell = if r.modified { "<em>Modified" } else { "Original" };
139	    format!(
140	        "<tr><td><a href=\"/thy/trace/{}/overview/help\">{}</a></td><td>{}</td><td>{}</td><td>{}</td></tr>",
141	        r.index,
142	        html_escape(r.name),
143	        r.time,
144	        version_cell,
145	        r.origin,
146	    )
147	}
148	
149	/// Render the index page (`GET /` / the `POST /` result page).
150	pub fn render_root(flash: Flash, version: &str, rows: &[RootRow]) -> String {
151	    let rows_html: String = rows.iter().map(render_root_row).collect();
152	    ROOT_TEMPLATE
153	        .replace("§FLASH§", flash.html())
154	        .replace("§VERSION§", version)
155	        .replace("§ROWS§", &rows_html)
156	}
