1	//! Round-3 byte-parity / behaviour tests for the interactive-UI state machine
2	//! (`web_clean::dispatch`).
3	//!
4	//! A `FakeProver` supplies the opaque prover fragments (canned to the values a
5	//! real theory would produce, taken from the live captures in
6	//! `tests/fixtures/r3_*`); the tests assert the *web-layer decisions* the state
7	//! machine makes around them: envelope shape, HTTP status/Location, theory-version
8	//! increments, and redirect-URL assembly. Every asserted string traces to a live
9	//! oracle observation (`QUERIES.log` [L8]–[L16]).
10	
11	use serde_json::Value;
12	use web_clean::dispatch::{
13	    Content, HttpMethod, MainReq, Meta, ProverOps, Request, RootMeta, Server,
14	};
15	use web_clean::intdot::EMPTY_GRAPH_DOT;
16	use web_clean::route::{Autoprove, AutoproveAll, AutoproveDiff, NavDir};
17	
18	// ---------------------------------------------------------------------------
19	// A minimal fake prover: holds lemma sources + canned fragments.
20	// ---------------------------------------------------------------------------
21	
22	#[derive(Clone)]
23	struct Thy {
24	    lemmas: Vec<(String, String)>, // (name, raw source)
25	}
26	
27	struct FakeProver;
28	
29	impl FakeProver {
30	    fn tutorial() -> Thy {
31	        Thy {
32	            lemmas: vec![
33	                (
34	                    "Client_auth".to_string(),
35	                    include_str!("fixtures/r3_lemma_text_client_auth.txt").to_string(),
36	                ),
37	                (
38	                    "Client_session_key_honest_setup".to_string(),
39	                    include_str!("fixtures/r3_lemma_text_honest_setup.txt").to_string(),
40	                ),
41	            ],
42	        }
43	    }
44	}
45	
46	impl ProverOps for FakeProver {
47	    type Theory = Thy;
48	
49	    fn meta(&self, _thy: &Thy) -> Meta {
50	        Meta { name: "Tutorial".into(), version: "1.13.0".into(), filename: "Tutorial.spthy".into() }
51	    }
52	    fn root_meta(&self, _thy: &Thy) -> RootMeta {
53	        RootMeta { time: "00:00:00".into(), origin: "Tutorial.spthy".into(), modified: false }
54	    }
55	    fn source_text(&self, _thy: &Thy) -> String {
56	        "theory Tutorial begin\nend".into()
57	    }
58	    fn west_pane(&self, _thy: &Thy, index: u64) -> String {
59	        format!("WEST@{index}")
60	    }
61	    fn main_content(&self, _thy: &Thy, index: u64, req: &MainReq) -> Content {
62	        // Canned; the real center-pane content is a prover fragment.
63	        let (kind, title) = match req {
64	            MainReq::Help => ("help", "Tutorial".to_string()),
65	            MainReq::Message => ("message", "Message theory".to_string()),
66	            MainReq::Rules => ("rules", "Rewriting rules".to_string()),
67	            MainReq::Tactic => ("tactic", "Tactics".to_string()),
68	            MainReq::Cases { .. } => ("cases", "Sources".to_string()),
69	            MainReq::Lemma(l) => ("lemma", format!("Lemma: {l}")),
70	            MainReq::Proof { lemma, .. } => ("proof", format!("Lemma: {lemma}")),
71	            MainReq::DiffProof { lemma, .. } => ("diffProof", format!("Lemma: {lemma}")),
72	            MainReq::DiffRules => ("diffrules", "Diff rules".to_string()),
73	        };
74	        Content { html: format!("<p>{kind}@{index}</p>"), title }
75	    }
76	    fn lemma_source(&self, thy: &Thy, name: &str) -> Option<String> {
77	        thy.lemmas.iter().find(|(n, _)| n == name).map(|(_, s)| s.clone())
78	    }
79	    fn graph_dot(&self, _thy: &Thy, _tail: &[String]) -> String {
80	        EMPTY_GRAPH_DOT.to_string()
81	    }
82	    fn nav_target(&self, _thy: &Thy, index: u64, dir: NavDir, _mode: &str, lemma: &str) -> String {
83	        // Canned to the live capture [L10] for (Next, Client_auth) at v1.
84	        match (dir, lemma) {
85	            (NavDir::Next, "Client_auth") => format!("/thy/trace/{index}/main/proof/Client_auth_injective"),
86	            (NavDir::Prev, "Client_auth") => format!("/thy/trace/{index}/main/proof/Client_session_key_secrecy"),
87	            _ => format!("/thy/trace/{index}/main/proof/{lemma}"),
88	        }
89	    }
90	    fn append_message(&self, _thy: &Thy) -> String {
91	        "Appended lemmas to /tmp/x/Tutorial.spthy".into()
