103	        thy.clone()
104	    }
105	    fn apply_method(&self, thy: &Thy, _lemma: &str, n: usize, _path: &[String]) -> Option<(Thy, Vec<String>)> {
106	        // Canned focus "_" as in the live method capture [L8]; method 0 = failure.
107	        (n != 0).then(|| (thy.clone(), vec!["_".to_string()]))
108	    }
