111	    }
112	    fn edit_lemma(&self, thy: &Thy, _name: &str, text: &str) -> Option<Thy> {
113	        // Model validity: a parseable lemma starts with the `lemma` keyword.
114	        text.trim_start().starts_with("lemma").then(|| thy.clone())
115	    }
116	    fn add_lemma(&self, thy: &Thy, _pos: &str, text: &str) -> Option<Thy> {
117	        text.trim_start().starts_with("lemma").then(|| thy.clone())
118	    }
119	    fn delete_lemma(&self, thy: &Thy, name: &str) -> Option<Thy> {
120	        // Some = found & removed; None = lemma not present.
121	        thy.lemmas.iter().any(|(n, _)| n == name).then(|| {
122	            let mut t = thy.clone();
123	            t.lemmas.retain(|(n, _)| n != name);
124	            t
125	        })
126	    }
127	    fn lemma_present(&self, thy: &Thy, lemma: &str) -> bool {
128	        thy.lemmas.iter().any(|(n, _)| n == lemma)
129	    }
130	    fn del_lemma_path(&self, thy: &Thy, name: &str) -> Option<Thy> {
131	        // Deletable iff the lemma exists; the modified theory is a fresh version.
132	        thy.lemmas.iter().any(|(n, _)| n == name).then(|| thy.clone())
133	    }
134	    fn del_proof_step(&self, thy: &Thy, lemma: &str, _path: &[String], _diff: bool) -> Option<Thy> {
135	        thy.lemmas.iter().any(|(n, _)| n == lemma).then(|| thy.clone())
136	    }
137	    fn apply_diff_method(&self, thy: &Thy, _lemma: &str, n: usize, _path: &[String]) -> Option<(Thy, Vec<String>)> {
138	        (n != 0).then(|| (thy.clone(), vec!["Rule_1".to_string()]))
139	    }
140	    fn autoprove_diff(&self, thy: &Thy, _spec: &AutoproveDiff) -> (Thy, Vec<String>) {
141	        (thy.clone(), vec!["Rule_1".to_string()])
142	    }
143	    fn autoprove_all(&self, thy: &Thy, _spec: &AutoproveAll) -> Thy {
144	        thy.clone()
145	    }
