37	// ---------------------------------------------------------------------------
38	// JSON envelopes: reproduce every captured json body from its parsed slots.
39	// ---------------------------------------------------------------------------
40	
41	fn check_all_envelopes(manifest_json: &str) -> (usize, usize) {
42	    let entries: Vec<Value> = serde_json::from_str(manifest_json).unwrap();
43	    let (mut content, mut redirect) = (0usize, 0usize);
44	    for e in &entries {
45	        let body = e["body"].as_str().unwrap();
46	        let parsed: Value = serde_json::from_str(body).unwrap();
47	        let obj = parsed.as_object().unwrap();
48	        if let Some(r) = obj.get("redirect") {
49	            let got = render_redirect(r.as_str().unwrap());
50	            assert_eq!(got, body, "redirect envelope mismatch for {}", e["route"]);
51	            redirect += 1;
52	        } else {
53	            let html = obj["html"].as_str().unwrap();
54	            let title = obj["title"].as_str().unwrap();
55	            let got = render_content(html, title);
56	            assert_eq!(got, body, "content envelope mismatch for {}", e["route"]);
57	            content += 1;
58	        }
59	    }
60	    (content, redirect)
61	}
