336	// ---------------------------------------------------------------------------
337	// Multi-theory HTML page generality (a committed sample of the corpus-wide
338	// harness in `examples/corpus_html.rs`). Reproduces both html families —
339	// `intdot` mini-pages and `overview/*` full shells — across six distinct
340	// theories and four theory-version indices, byte-for-byte. The intdot bodies
341	// are rendered fully from the model (theory name + request index + URL tail);
342	// the overview shells are reproduced with the west/center pane inner HTML
343	// treated as opaque prover/proof fragments, exactly as the single-page shell
344	// tests above. See workspace/REPORT2.md for the full-corpus percentages.
345	// ---------------------------------------------------------------------------
346	
347	#[derive(Deserialize)]
348	struct HtmlRec {
349	    name: String,
350	    ver: String,
351	    file: String,
352	    u: String,
353	    b: String,
354	}
355	
356	fn index_after(body: &str, needle: &str) -> Option<u64> {
357	    let start = body.find(needle)? + needle.len();
358	    body[start..]
359	        .chars()
360	        .take_while(|c| c.is_ascii_digit())
361	        .collect::<String>()
362	        .parse()
363	        .ok()
364	}
365	
366	fn between<'a>(body: &'a str, open: &str, close: &str) -> Option<&'a str> {
367	    let a = body.find(open)? + open.len();
368	    let b = body[a..].find(close)? + a;
369	    Some(&body[a..b])
370	}
371	
372	#[test]
373	fn html_page_generality_sample_byte_identical() {
374	    use web_clean::intdot::{dotsrc_path, render_intdot};
375	
376	    const WEST_OPEN: &str = r#"<div class="monospace" id="proof">"#;
377	    const WEST_CLOSE: &str = r#"</div></div></div><div class="ui-layout-east">"#;
378	    const CENTER_OPEN: &str = r#"<div id="ui-main-display">"#;
379	    const CENTER_CLOSE: &str = r#"</div></div></div><div id="dialog">"#;
380	
381	    let sample = include_str!("fixtures/html_sample.ndjson");
382	    let (mut intdot, mut overview) = (0usize, 0usize);
383	    for line in sample.lines().filter(|l| !l.trim().is_empty()) {
384	        let r: HtmlRec = serde_json::from_str(line).unwrap();
385	        let rest = r.u.strip_prefix("/thy/trace/#/").unwrap();
386	        let (handler, tail) = rest.split_once('/').unwrap_or((rest, ""));
387	        match handler {
388	            "intdot" => {
389	                // The only value read from the target is the erased request
390	                // index; name (sibling page) and tail (URL) are independent.
391	                let idx = index_after(&r.b, "dotsrc=\"/thy/trace/").unwrap();
392	                let got = render_intdot(&r.name, &dotsrc_path(idx, tail));
393	                assert_eq!(got, r.b, "intdot mismatch for {}", r.u);
394	                intdot += 1;
395	            }
396	            "overview" => {
397	                let idx = index_after(&r.b, "action=\"/thy/trace/").unwrap();
398	                let west = between(&r.b, WEST_OPEN, WEST_CLOSE).unwrap();
399	                let center = between(&r.b, CENTER_OPEN, CENTER_CLOSE).unwrap();
400	                let params = PageParams {
401	                    theory_name: &r.name,
402	                    index: idx,
403	                    version: &r.ver,
404	                    filename: &r.file,
405	                };
406	                assert_eq!(render_page(&params, west, center), r.b, "overview mismatch for {}", r.u);
407	                overview += 1;
408	            }
409	            other => panic!("unexpected html handler {other:?}"),
410	        }
411	    }
412	    assert!(intdot >= 8 && overview >= 10, "sample coverage regressed: {intdot} intdot / {overview} overview");
413	}
