1	//! Round-4 byte-parity / behaviour tests for the full request surface: the
2	//! top-level routes (`/`, `/robots.txt`, `/favicon.ico`, `/kill`, `/static/**`),
3	//! the theory-scoped `reload` / `download` / `get_and_append`, the diff (equiv)
4	//! shell and proof ops, and the refined version lifecycle (upload / reload /
5	//! delete-not-found / method-failure).
6	//!
7	//! Every asserted string traces to a live oracle observation captured under
8	//! `tests/fixtures/r4_*` (see `QUERIES.log` round 4). A `FakeProver` supplies the
9	//! opaque prover fragments; the tests assert the web-layer decisions around them.
10	
11	use web_clean::dispatch::{
12	    Content, HttpMethod, MainReq, Meta, ProverOps, Request, RootMeta, Server,
13	};
14	use web_clean::page::{render_page_kind, render_root, Flash, PageParams, RootRow, ShellKind};
15	use web_clean::route::{Autoprove, AutoproveAll, AutoproveDiff, NavDir, Toplevel};
