33	impl ProverOps for Fake {
34	    type Theory = Thy;
35	
36	    fn meta(&self, thy: &Thy) -> Meta {
37	        Meta { name: thy.name.clone(), version: "1.13.0".into(), filename: format!("{}.spthy", thy.name) }
38	    }
39	    fn root_meta(&self, thy: &Thy) -> RootMeta {
40	        RootMeta { time: "00:00:00".into(), origin: format!("{}.spthy", thy.name), modified: false }
41	    }
42	    fn source_text(&self, thy: &Thy) -> String {
43	        format!("theory {} begin\nend", thy.name)
44	    }
45	    fn west_pane(&self, _thy: &Thy, index: u64) -> String {
46	        format!("WEST@{index}")
47	    }
48	    fn main_content(&self, _thy: &Thy, index: u64, req: &MainReq) -> Content {
49	        let (k, t) = match req {
50	            MainReq::Help => ("help", "Help".to_string()),
51	            MainReq::Message => ("message", "Message".to_string()),
52	            MainReq::Rules => ("rules", "Rules".to_string()),
53	            MainReq::Tactic => ("tactic", "Tactic".to_string()),
54	            MainReq::Cases { .. } => ("cases", "Cases".to_string()),
55	            MainReq::Lemma(l) => ("lemma", format!("Lemma: {l}")),
56	            MainReq::Proof { lemma, .. } => ("proof", format!("Lemma: {lemma}")),
57	            MainReq::DiffProof { lemma, .. } => ("diffProof", format!("Lemma: {lemma}")),
58	            MainReq::DiffRules => ("diffrules", "Diff rules".to_string()),
59	        };
60	        Content { html: format!("<p>{k}@{index}</p>"), title: t }
61	    }
62	    fn lemma_source(&self, _thy: &Thy, name: &str) -> Option<String> {
63	        Some(format!("lemma {name}: exists-trace \"T\""))
64	    }
65	    fn graph_dot(&self, _thy: &Thy, _tail: &[String]) -> String {
66	        web_clean::intdot::EMPTY_GRAPH_DOT.to_string()
67	    }
68	    fn nav_target(&self, _thy: &Thy, index: u64, _dir: NavDir, _mode: &str, lemma: &str) -> String {
69	        format!("/thy/trace/{index}/main/proof/{lemma}")
70	    }
71	    fn append_message(&self, _thy: &Thy) -> String {
72	        "Appended lemmas to /tmp/x/Tutorial.spthy".into()
73	    }
74	    fn static_file(&self, path: &[String]) -> Option<Vec<u8>> {
75	        (path == ["css".to_string(), "app.css".to_string()]).then(|| b"body{}".to_vec())
76	    }
77	    fn load_theory(&self, source: &str) -> Option<Thy> {
78	        source.contains("theory").then(|| Thy { name: "NSLPK3".into(), lemmas: vec![] })
79	    }
80	    fn reload(&self, thy: &Thy) -> Thy {
81	        thy.clone()
82	    }
83	    fn apply_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
84	        (n != 0).then(|| (thy.clone(), vec!["_".to_string()]))
85	    }
86	    fn autoprove(&self, thy: &Thy, _s: &Autoprove) -> (Thy, Vec<String>) {
87	        (thy.clone(), vec!["_".to_string()])
88	    }
89	    fn edit_lemma(&self, thy: &Thy, _n: &str, text: &str) -> Option<Thy> {
90	        text.trim_start().starts_with("lemma").then(|| thy.clone())
91	    }
92	    fn add_lemma(&self, thy: &Thy, _p: &str, text: &str) -> Option<Thy> {
93	        text.trim_start().starts_with("lemma").then(|| thy.clone())
94	    }
95	    fn delete_lemma(&self, thy: &Thy, name: &str) -> Option<Thy> {
96	        thy.lemmas.iter().any(|l| l == name).then(|| {
97	            let mut t = thy.clone();
