103	        thy.lemmas.iter().any(|l| l == lemma)
104	    }
105	    fn del_lemma_path(&self, thy: &Thy, name: &str) -> Option<Thy> {
106	        thy.lemmas.iter().any(|l| l == name).then(|| thy.clone())
107	    }
108	    fn del_proof_step(&self, thy: &Thy, lemma: &str, _path: &[String], _diff: bool) -> Option<Thy> {
109	        thy.lemmas.iter().any(|l| l == lemma).then(|| thy.clone())
110	    }
111	    fn apply_diff_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
112	        (n != 0).then(|| (thy.clone(), vec!["Rule_Destrd_0_fst".to_string()]))
113	    }
114	    fn autoprove_diff(&self, thy: &Thy, _s: &AutoproveDiff) -> (Thy, Vec<String>) {
115	        (thy.clone(), vec!["Rule_Destrd_0_fst".to_string()])
116	    }
117	    fn autoprove_all(&self, thy: &Thy, _s: &AutoproveAll) -> Thy {
118	        thy.clone()
119	    }
120	}
