1	//! Round-5 byte-parity / behaviour tests for the `del/path/…` and `verify/…`
2	//! route families (BEHAVIOR.md §15; QUERIES.log [R50]–[R57]).
3	//!
4	//! Every asserted string traces to a live oracle observation of theory
5	//! `RevealingSignatures` (regression/trace/issue193.spthy, one exists-trace lemma
6	//! `debug`) plus the four staged captures in `round5/` (`del_path.json`,
7	//! `del_path_bad.json`, `verify.json`, `verify_proof.json`). A `FakeProver` supplies
8	//! the opaque prover fragments (lemma-existence model + a canned help pane); the
9	//! tests assert the WEB-LAYER decisions around them: route match (404) vs method
10	//! (405), envelope shape, redirect target, version allocation, and alert selection.
11	
12	use web_clean::dispatch::{Content, MainReq, Meta, ProverOps, Request, RootMeta, Server};
13	use web_clean::route::{Autoprove, AutoproveAll, AutoproveDiff, NavDir, Route, ThyPath};
14	
15	// ---------------------------------------------------------------------------
16	// A fake prover that models lemma existence (the one datum del/path + verify need)
17	// and returns a canned help pane. `del`/`verify` never inspect proof internals.
18	// ---------------------------------------------------------------------------
19	
20	#[derive(Clone)]
21	struct Thy {
22	    name: String,
23	    lemmas: Vec<String>,
24	}
25	
26	struct Fake;
27	
28	fn trace_base() -> Thy {
29	    Thy { name: "RevealingSignatures".into(), lemmas: vec!["debug".into()] }
30	}
31	fn equiv_base() -> Thy {
32	    Thy { name: "KCL07_UK1_attack_manual".into(), lemmas: vec!["Observational_equivalence".into()] }
33	}
34	
35	// The help content the FakeProver returns for MainReq::Help — the exact fragment
36	// is a prover concern; verify must return *this same* envelope for every
37	// non-redirecting path (that is the web-layer claim under test).
38	const HELP_HTML: &str = "<p>Theory: RevealingSignatures</p><div id=\"help\">…</div>";
39	
40	impl ProverOps for Fake {
41	    type Theory = Thy;
42	
43	    fn meta(&self, thy: &Thy) -> Meta {
44	        Meta { name: thy.name.clone(), version: "1.13.0".into(), filename: format!("{}.spthy", thy.name) }
45	    }
46	    fn root_meta(&self, thy: &Thy) -> RootMeta {
47	        RootMeta { time: "00:00:00".into(), origin: format!("{}.spthy", thy.name), modified: false }
48	    }
49	    fn source_text(&self, thy: &Thy) -> String {
50	        format!("theory {} begin\nend", thy.name)
51	    }
52	    fn west_pane(&self, _thy: &Thy, index: u64) -> String {
53	        format!("WEST@{index}")
54	    }
55	    fn main_content(&self, thy: &Thy, _index: u64, req: &MainReq) -> Content {
56	        match req {
57	            // verify's non-redirect branch renders the help pane; assert its exact
58	            // envelope round-trips through the web layer unchanged.
59	            MainReq::Help => Content { html: HELP_HTML.to_string(), title: format!("Theory: {}", thy.name) },
60	            _ => Content { html: "<p>other</p>".to_string(), title: "other".to_string() },
61	        }
62	    }
63	    fn lemma_source(&self, _thy: &Thy, _name: &str) -> Option<String> {
64	        Some("lemma debug: exists-trace \"T\"".into())
65	    }
66	    fn graph_dot(&self, _thy: &Thy, _tail: &[String]) -> String {
67	        web_clean::intdot::EMPTY_GRAPH_DOT.to_string()
68	    }
69	    fn nav_target(&self, _thy: &Thy, index: u64, _dir: NavDir, _mode: &str, lemma: &str) -> String {
70	        format!("/thy/trace/{index}/main/proof/{lemma}")
71	    }
72	    fn append_message(&self, _thy: &Thy) -> String {
73	        "Appended lemmas to /tmp/x/issue193.spthy".into()
74	    }
75	    fn static_file(&self, _path: &[String]) -> Option<Vec<u8>> {
76	        None
77	    }
78	    fn load_theory(&self, source: &str) -> Option<Thy> {
79	        source.contains("theory").then(|| Thy { name: "NSLPK3".into(), lemmas: vec![] })
80	    }
81	    fn reload(&self, thy: &Thy) -> Thy {
82	        thy.clone()
83	    }
84	    fn apply_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
85	        (n != 0).then(|| (thy.clone(), vec!["_".to_string()]))
86	    }
87	    fn autoprove(&self, thy: &Thy, _s: &Autoprove) -> (Thy, Vec<String>) {
88	        (thy.clone(), vec!["_".to_string()])
89	    }
90	    fn edit_lemma(&self, thy: &Thy, _n: &str, _t: &str) -> Option<Thy> {
91	        Some(thy.clone())
92	    }
93	    fn add_lemma(&self, thy: &Thy, _p: &str, _t: &str) -> Option<Thy> {
94	        Some(thy.clone())
95	    }
96	    fn delete_lemma(&self, thy: &Thy, name: &str) -> Option<Thy> {
97	        thy.lemmas.iter().any(|l| l == name).then(|| thy.clone())
98	    }
99	    fn apply_diff_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
100	        (n != 0).then(|| (thy.clone(), vec!["Rule".to_string()]))
101	    }
102	    fn autoprove_diff(&self, thy: &Thy, _s: &AutoproveDiff) -> (Thy, Vec<String>) {
103	        (thy.clone(), vec!["Rule".to_string()])
104	    }
105	    fn autoprove_all(&self, thy: &Thy, _s: &AutoproveAll) -> Thy {
106	        thy.clone()
107	    }
108	    // ---- round-5 additions: del/path + verify ----
109	    fn lemma_present(&self, thy: &Thy, lemma: &str) -> bool {
110	        thy.lemmas.iter().any(|l| l == lemma)
111	    }
112	    fn del_lemma_path(&self, thy: &Thy, name: &str) -> Option<Thy> {
113	        thy.lemmas.iter().any(|l| l == name).then(|| thy.clone())
114	    }
115	    fn del_proof_step(&self, thy: &Thy, lemma: &str, _path: &[String], _diff: bool) -> Option<Thy> {
116	        thy.lemmas.iter().any(|l| l == lemma).then(|| thy.clone())
117	    }
118	}
