1	//! Corpus-wide byte-parity harness for the two HTML page families.
2	//!
3	//! Reads an NDJSON extract of every `kind == "html"` response body across all
4	//! captured crawl manifests (one JSON object per line, produced by the jq
5	//! extractor documented in `workspace/REPORT2.md`), renders each body from the
6	//! crate's own templates using inputs taken from *observable* sources, and
7	//! reports per-family byte-exact reproduction counts.
8	//!
9	//! Run: `cargo run --release --example corpus_html -- <html_corpus.ndjson>`
10	//!
11	//! Each input record is `{mf, name, ver, file, u, b}`:
12	//! * `mf`   — manifest id (for diagnostics only)
13	//! * `name` — theory name, taken once per manifest from that manifest's
14	//!   `overview/help` `<title>` (a sibling artifact, not this body)
15	//! * `ver`  — Tamarin version, likewise from `overview/help`
16	//! * `file` — source filename, likewise from `overview/help`
17	//! * `u`    — the request URL key (index normalised to `#` by the capture tool)
18	//! * `b`    — the captured response body we must reproduce
19	//!
20	//! Non-circularity: for the `intdot` family the only value read back from the
21	//! target body `b` is the scalar request index (the `#` the capture erased); the
22	//! theory name comes from a sibling page and the path tail comes from the URL
23	//! key, so a byte match proves the template, name placement and tail-passthrough
24	//! independently. For the `overview` family the west/center pane inner HTML are
25	//! treated as opaque fragments (prover/proof-state output) exactly as the
26	//! committed page tests do; the harness measures whether the crate's shell
27	//! scaffolding + slot substitution reproduces the surrounding page bytes.
28	
29	use std::collections::BTreeMap;
30	use std::io::{BufRead, BufReader};
31	
32	use serde::Deserialize;
33	use web_clean::intdot::{dotsrc_path, render_intdot};
34	use web_clean::page::{render_page, PageParams};
35	
36	#[derive(Deserialize)]
37	struct Rec {
38	    #[allow(dead_code)]
39	    mf: String,
40	    name: String,
41	    ver: String,
42	    file: String,
43	    u: String,
44	    b: String,
45	}
46	
47	/// Split `/thy/trace/#/<handler>/<tail>` into (handler, tail).
48	fn handler_and_tail(u: &str) -> Option<(&str, &str)> {
49	    let rest = u.strip_prefix("/thy/trace/#/")?;
50	    match rest.split_once('/') {
51	        Some((h, t)) => Some((h, t)),
52	        None => Some((rest, "")),
53	    }
54	}
55	
56	/// Read the decimal index that follows `needle` in `body` (e.g. the request
57	/// index the capture tool normalised to `#`, recovered from an emitted link).
58	fn index_after(body: &str, needle: &str) -> Option<u64> {
59	    let start = body.find(needle)? + needle.len();
60	    let digits: String = body[start..].chars().take_while(|c| c.is_ascii_digit()).collect();
61	    digits.parse().ok()
62	}
63	
64	/// Extract the substring of `body` strictly between `open` and the next `close`
65	/// occurring after it.
66	fn between<'a>(body: &'a str, open: &str, close: &str) -> Option<&'a str> {
67	    let a = body.find(open)? + open.len();
68	    let b = body[a..].find(close)? + a;
69	    Some(&body[a..b])
70	}
71	
72	// Fixed pane delimiters (observed; the same bytes the page shell uses).
73	const WEST_OPEN: &str = r#"<div class="monospace" id="proof">"#;
74	const WEST_CLOSE: &str = r#"</div></div></div><div class="ui-layout-east">"#;
75	const CENTER_OPEN: &str = r#"<div id="ui-main-display">"#;
76	const CENTER_CLOSE: &str = r#"</div></div></div><div id="dialog">"#;
77	
78	#[derive(Default)]
79	struct Tally {
80	    total: usize,
81	    ok: usize,
82	    /// example failing URL (first seen)
83	    first_fail: Option<String>,
84	}
85	impl Tally {
86	    fn record(&mut self, ok: bool, u: &str) {
87	        self.total += 1;
88	        if ok {
89	            self.ok += 1;
90	        } else if self.first_fail.is_none() {
91	            self.first_fail = Some(u.to_string());
92	        }
93	    }
94	    fn pct(&self) -> f64 {
95	        if self.total == 0 {
96	            0.0
97	        } else {
98	            100.0 * self.ok as f64 / self.total as f64
99	        }
100	    }
101	}
102	
103	fn overview_subfamily(tail: &str) -> &'static str {
104	    if tail == "help" {
105	        "overview/help"
106	    } else if tail.starts_with("proof/") {
107	        "overview/proof"
108	    } else {
109	        "overview/other"
110	    }
111	}
112	
113	fn main() {
114	    let path = std::env::args().nth(1).expect("usage: corpus_html <ndjson>");
115	    let f = std::fs::File::open(&path).expect("open corpus");
116	    let reader = BufReader::new(f);
117	
118	    let mut intdot = Tally::default();
119	    let mut intdot_name_guard_fail = 0usize;
120	    let mut intdot_tail_guard_fail = 0usize;
121	    let mut overview: BTreeMap<&'static str, Tally> = BTreeMap::new();
122	    // center-pane linkage sub-metric: does the center pane end in the observed
123	    // single trailing space that distinguishes it from the raw main/* html?
124	    let mut center_trailing_space = Tally::default();
125	    let mut other_handler: BTreeMap<String, usize> = BTreeMap::new();
126	    let mut parse_errors = 0usize;
127	
128	    for line in reader.lines() {
129	        let line = line.expect("read line");
130	        if line.trim().is_empty() {
131	            continue;
132	        }
133	        let r: Rec = match serde_json::from_str(&line) {
134	            Ok(r) => r,
135	            Err(_) => {
136	                parse_errors += 1;
137	                continue;
138	            }
139	        };
140	        let Some((handler, tail)) = handler_and_tail(&r.u) else {
141	            *other_handler.entry(r.u.clone()).or_default() += 1;
142	            continue;
143	        };
144	
145	        match handler {
146	            "intdot" => {
147	                // idx: the one value read from the target (the erased request index).
148	                let idx = match index_after(&r.b, "dotsrc=\"/thy/trace/") {
149	                    Some(i) => i,
150	                    None => {
151	                        intdot.record(false, &r.u);
152	                        continue;
153	                    }
154	                };
155	                // Non-circularity guards (independent of the byte compare):
156	                //  - the name shown in the body matches the sibling-derived name
157	                //  - the path tail echoed in dotsrc matches the URL key tail
158	                if let Some(bn) = between(&r.b, "<title>Theory: ", "</title>") {
159	                    if bn != r.name {
160	                        intdot_name_guard_fail += 1;
161	                    }
162	                }
163	                if let Some(bt) = between(&r.b, "interactive-graph-def/", "\"") {
164	                    if bt != tail {
165	                        intdot_tail_guard_fail += 1;
166	                    }
167	                }
168	                let dotsrc = dotsrc_path(idx, tail);
169	                let got = render_intdot(&r.name, &dotsrc);
170	                intdot.record(got == r.b, &r.u);
171	            }
172	            "overview" => {
173	                let sub = overview_subfamily(tail);
174	                let idx = match index_after(&r.b, "action=\"/thy/trace/") {
175	                    Some(i) => i,
176	                    None => {
177	                        overview.entry(sub).or_default().record(false, &r.u);
178	                        continue;
179	                    }
180	                };
181	                let west = between(&r.b, WEST_OPEN, WEST_CLOSE);
182	                let center = between(&r.b, CENTER_OPEN, CENTER_CLOSE);
183	                let (west, center) = match (west, center) {
184	                    (Some(w), Some(c)) => (w, c),
185	                    _ => {
186	                        overview.entry(sub).or_default().record(false, &r.u);
187	                        continue;
188	                    }
189	                };
190	                let params = PageParams {
191	                    theory_name: &r.name,
192	                    index: idx,
193	                    version: &r.ver,
194	                    filename: &r.file,
195	                };
196	                let got = render_page(&params, west, center);
197	                overview.entry(sub).or_default().record(got == r.b, &r.u);
198	                center_trailing_space.record(center.ends_with(' '), &r.u);
199	            }
200	            _ => {
201	                *other_handler.entry(handler.to_string()).or_default() += 1;
202	            }
203	        }
204	    }
205	
206	    println!("== HTML corpus byte-parity ==");
207	    println!("input parse errors: {parse_errors}");
208	    println!();
209	    println!(
210	        "intdot           : {:>6}/{:<6} = {:6.2}%   (first fail: {:?})",
211	        intdot.ok,
212	        intdot.total,
213	        intdot.pct(),
214	        intdot.first_fail
215	    );
216	    println!(
217	        "  name guard fails: {intdot_name_guard_fail}   tail guard fails: {intdot_tail_guard_fail} (both must be 0)"
218	    );
219	    let mut ov_ok = 0;
220	    let mut ov_total = 0;
221	    for (sub, t) in &overview {
222	        ov_ok += t.ok;
223	        ov_total += t.total;
224	        println!(
225	            "{sub:<17}: {:>6}/{:<6} = {:6.2}%   (first fail: {:?})",
226	            t.ok,
227	            t.total,
228	            t.pct(),
229	            t.first_fail
230	        );
231	    }
232	    println!(
233	        "overview (all)   : {:>6}/{:<6} = {:6.2}%",
234	        ov_ok,
235	        ov_total,
236	        if ov_total == 0 { 0.0 } else { 100.0 * ov_ok as f64 / ov_total as f64 }
237	    );
238	    println!(
239	        "  center-pane trailing-space rule holds: {}/{} = {:.2}%",
240	        center_trailing_space.ok,
241	        center_trailing_space.total,
242	        center_trailing_space.pct()
243	    );
244	    if !other_handler.is_empty() {
245	        println!("\nunexpected handlers (should be none):");
246	        for (h, n) in &other_handler {
247	            println!("  {h}: {n}");
248	        }
249	    }
250	    let grand_ok = intdot.ok + ov_ok;
251	    let grand_total = intdot.total + ov_total;
252	    println!(
253	        "\nALL html         : {:>6}/{:<6} = {:6.2}%",
254	        grand_ok,
255	        grand_total,
256	        if grand_total == 0 { 0.0 } else { 100.0 * grand_ok as f64 / grand_total as f64 }
257	    );
258	}
